import {
  MARKER_CONTENT_TO_BORDER_PADDING,
  MARKER_STROKE_WIDTH,
} from '../../../../../constants.js';
import { CANVAS_PIXEL_OFFSET } from '../../../constants.js';
import { VALUE_MARKER_WIDTH } from '../constants.js';
import { ValueMarkerPointerPosition } from '../types.js';

const PADDING_X =
  MARKER_CONTENT_TO_BORDER_PADDING - MARKER_STROKE_WIDTH - CANVAS_PIXEL_OFFSET;

export const calculateCenteredIcon = (
  x: number,
  orientation: ValueMarkerPointerPosition,
) => {
  switch (orientation) {
    case 'center': {
      return x - VALUE_MARKER_WIDTH / 2 + PADDING_X;
    }
    case 'right': {
      return (
        x -
        VALUE_MARKER_WIDTH -
        MARKER_STROKE_WIDTH +
        MARKER_CONTENT_TO_BORDER_PADDING
      );
    }
    case 'left': {
      return x + PADDING_X;
    }
  }
};
